class PWAInstaller{constructor(){this.deferredPrompt=null;this.installBtn=null;this.init();}init(){window.addEventListener('beforeinstallprompt',(e)=>{e.preventDefault();this.deferredPrompt=e;this.showInstallPromotion();});window.addEventListener('appinstalled',()=>{this.deferredPrompt=null;this.hideInstallPromotion();});if('serviceWorker' in navigator){window.addEventListener('load',()=>{navigator.serviceWorker.register('/sw.js').then(registration=>{}).catch(err=>{});});}}showInstallPromotion(){const btn=document.getElementById('pwa-install-btn');if(btn){btn.style.display='flex';btn.addEventListener('click',()=>this.install());}}hideInstallPromotion(){const btn=document.getElementById('pwa-install-btn');if(btn){btn.style.display='none';}}async install(){if(!this.deferredPrompt){this.showIOSInstructions();return;}this.deferredPrompt.prompt();const{outcome}=await this.deferredPrompt.userChoice;this.deferredPrompt=null;this.hideInstallPromotion();}showIOSInstructions(){const isIOS=/iPad|iPhone|iPod/.test(navigator.userAgent)&&!window.MSStream;if(isIOS){alert('Để cài đặt trên iOS:\n1. Nhấn nút "Chia sẻ"(Share)\n2. Chọn "Thêm vào MH chính"(Add to Home Screen)');}}}window.PWA=new PWAInstaller();